package ai.holo.wdyt.subscription.service;

import ai.holo.wdyt.subscription.model.dto.AppleNotificationPayload;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.Test;

import java.util.Map;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class AppleJwsVerificationServiceTest {

    @Test
    public void testVerifyAndDecodeSignedPayload() {
        AppleJwsVerificationService appleJwsVerificationService = new AppleJwsVerificationService(new ObjectMapper(), Map.of("appleSubscriptionKey", "MIGTAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBHkwdwIBAQQgTCZOn86PYlJanZc5Juu7BqxhBeagFy19vTxB84BvlYKgCgYIKoZIzj0DAQehRANCAASxgXOOt6gt8GOjvhLzXw",
                "appleSubscriptionKidId", "Apple_Xcode_Key"));
        AppleNotificationPayload appleNotificationPayload = appleJwsVerificationService.verifyAndDecodeNotification("..gOKs6u4aA7lgukyc7LE9pA_W7IfCN9hTDvT-a_zUqasGyeEskn7g2Vh0DfGx_mNcu6tfFbYLg_cvQr7Rwl1gxg");
        assertEquals("ONE_TIME_CHARGE", appleNotificationPayload.notificationType());
        assertEquals("..ouNWIH-gDTsckPlUQXvcMlmg70oN2noTVoVYyVDI0c8OHOCLjjRIGQhNx34tl3pQAWwEz_RjO4PwedM8BzBFsQ", appleNotificationPayload.data().signedTransactionInfo());
    }
}
